import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Check, X, Loader2, ArrowRight, MessageSquare } from "lucide-react";
import { toast } from "sonner";

const AdminLandmarkEdits = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [statusFilter, setStatusFilter] = useState("pending");
  const [reviewDialog, setReviewDialog] = useState<any>(null);
  const [adminNote, setAdminNote] = useState("");

  const { data: edits = [], isLoading } = useQuery({
    queryKey: ["admin-landmark-edits", statusFilter],
    queryFn: async () => {
      let query = supabase
        .from("landmark_edits")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(100);

      if (statusFilter !== "all") {
        query = query.eq("status", statusFilter);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
  });

  // Fetch landmark names for display
  const landmarkIds = [...new Set(edits.map((e: any) => e.landmark_id))];
  const { data: landmarks = [] } = useQuery({
    queryKey: ["landmark-names", landmarkIds],
    queryFn: async () => {
      if (landmarkIds.length === 0) return [];
      const { data } = await supabase
        .from("restaurants")
        .select("id, name")
        .in("id", landmarkIds);
      return data || [];
    },
    enabled: landmarkIds.length > 0,
  });

  const getLandmarkName = (id: string) => {
    const lm = landmarks.find((l: any) => l.id === id);
    return lm?.name || id.slice(0, 8);
  };

  const reviewMutation = useMutation({
    mutationFn: async ({ editId, action, note }: { editId: string; action: "approved" | "rejected"; note: string }) => {
      const edit = edits.find((e: any) => e.id === editId);

      // Update edit status
      const { error } = await supabase
        .from("landmark_edits")
        .update({
          status: action,
          admin_note: note || null,
          reviewed_at: new Date().toISOString(),
        })
        .eq("id", editId);
      if (error) throw error;

      // If approving, apply the edit via moderation function
      if (action === "approved" && edit) {
        await supabase.functions.invoke("moderate-landmark-edit", {
          body: { editId },
        });
      }

      // If rejected, notify user
      if (action === "rejected" && edit) {
        const noteText = note ? ` ${note}` : "";
        await supabase.from("notifications").insert({
          user_id: edit.user_id,
          type: "landmark_edit" as any,
          title: `[[MULTILANG]]${JSON.stringify({ zh: "景点编辑未通过", en: "Landmark Edit Rejected", pt: "Edição de ponto turístico rejeitada" })}`,
          content: `[[MULTILANG]]${JSON.stringify({ zh: `您对「${edit.field_name}」的编辑未通过审核。${noteText}`, en: `Your edit to "${edit.field_name}" was rejected.${noteText}`, pt: `A sua edição de "${edit.field_name}" foi rejeitada.${noteText}` })}`,
          link: `/landmark/${edit.landmark_id}`,
          read: false,
        });
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-edits"] });
      toast.success(t("admin.landmarkEdits.reviewSuccess"));
      setReviewDialog(null);
      setAdminNote("");
    },
    onError: () => {
      toast.error(t("admin.landmarkEdits.reviewFailed"));
    },
  });

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending": return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-200">{t("admin.landmarkEdits.pending")}</Badge>;
      case "approved": return <Badge className="bg-green-100 text-green-700 border-green-200">{t("admin.landmarkEdits.approved")}</Badge>;
      case "rejected": return <Badge variant="destructive">{t("admin.landmarkEdits.rejected")}</Badge>;
      default: return <Badge variant="secondary">{status}</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">{t("admin.landmarkEdits.title")}</h1>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-[150px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{t("admin.landmarkEdits.all")}</SelectItem>
            <SelectItem value="pending">{t("admin.landmarkEdits.pending")}</SelectItem>
            <SelectItem value="approved">{t("admin.landmarkEdits.approved")}</SelectItem>
            <SelectItem value="rejected">{t("admin.landmarkEdits.rejected")}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Card>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
            </div>
          ) : edits.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              {t("admin.landmarkEdits.empty")}
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>{t("admin.landmarkEdits.landmark")}</TableHead>
                  <TableHead>{t("admin.landmarkEdits.field")}</TableHead>
                  <TableHead>{t("admin.landmarkEdits.change")}</TableHead>
                  <TableHead>{t("admin.landmarkEdits.lang")}</TableHead>
                  <TableHead>{t("admin.landmarkEdits.status")}</TableHead>
                  <TableHead>{t("admin.landmarkEdits.ai")}</TableHead>
                  <TableHead className="w-32">{t("admin.landmarkEdits.actions")}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {edits.map((edit: any) => (
                  <TableRow key={edit.id}>
                    <TableCell className="font-medium max-w-[120px] truncate">
                      {getLandmarkName(edit.landmark_id)}
                    </TableCell>
                    <TableCell className="text-sm">{edit.field_name}</TableCell>
                    <TableCell className="max-w-[200px]">
                      <div className="text-xs space-y-0.5">
                        <div className="text-muted-foreground line-through truncate">{edit.old_value || "(空)"}</div>
                        <div className="flex items-center gap-1">
                          <ArrowRight className="w-3 h-3 text-primary shrink-0" />
                          <span className="truncate font-medium">{edit.new_value}</span>
                        </div>
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant="secondary" className="text-xs">{edit.edit_lang}</Badge>
                    </TableCell>
                    <TableCell>{getStatusBadge(edit.status)}</TableCell>
                    <TableCell>
                      {edit.ai_review_result && (
                        <Badge variant={edit.ai_review_result.decision === "approved" ? "secondary" : "outline"} className="text-xs">
                          {edit.ai_review_result.decision === "approved" ? "✓ AI" : "⚠ AI"}
                        </Badge>
                      )}
                    </TableCell>
                    <TableCell>
                      {edit.status === "pending" && (
                        <div className="flex gap-1">
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-7 px-2 text-green-600"
                            onClick={() => reviewMutation.mutate({ editId: edit.id, action: "approved", note: "" })}
                          >
                            <Check className="w-3.5 h-3.5" />
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-7 px-2 text-destructive"
                            onClick={() => { setReviewDialog(edit); setAdminNote(""); }}
                          >
                            <X className="w-3.5 h-3.5" />
                          </Button>
                        </div>
                      )}
                      {edit.admin_note && (
                        <MessageSquare className="w-3.5 h-3.5 text-muted-foreground inline ml-1" />
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Reject dialog */}
      <Dialog open={!!reviewDialog} onOpenChange={() => setReviewDialog(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.landmarkEdits.rejectTitle")}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div className="text-sm">
              <span className="text-muted-foreground">{t("admin.landmarkEdits.field")}:</span> {reviewDialog?.field_name}
            </div>
            <div className="text-sm">
              <span className="text-muted-foreground">{t("admin.landmarkEdits.newValue")}:</span> {reviewDialog?.new_value}
            </div>
            <Textarea
              value={adminNote}
              onChange={(e) => setAdminNote(e.target.value)}
              placeholder={t("admin.landmarkEdits.rejectReason")}
              className="min-h-[80px]"
            />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setReviewDialog(null)}>
              {t("common.cancel")}
            </Button>
            <Button
              variant="destructive"
              onClick={() => reviewMutation.mutate({ editId: reviewDialog.id, action: "rejected", note: adminNote })}
              disabled={reviewMutation.isPending}
            >
              {t("admin.landmarkEdits.confirmReject")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminLandmarkEdits;
